import React, { useState } from 'react';
import './App.css';
import StructureAnalyser from './StructureAnalyser';
import BlueprintUploader from './BlueprintUploader';
import StructureBuilder from './StructureBuilder';

function App() {
  const [activeTab, setActiveTab] = useState('builder');

  const renderActiveComponent = () => {
    switch (activeTab) {
      case 'analyser':
        return <StructureAnalyser />;
      case 'uploader':
        return <BlueprintUploader />;
      case 'builder':
      default:
        return <StructureBuilder />;
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <nav className="App-nav">
          <button onClick={() => setActiveTab('builder')} className={activeTab === 'builder' ? 'active' : ''}>
            Structure Builder
          </button>
          <button onClick={() => setActiveTab('analyser')} className={activeTab === 'analyser' ? 'active' : ''}>
            Structure Analyser
          </button>
          <button onClick={() => setActiveTab('uploader')} className={activeTab === 'uploader' ? 'active' : ''}>
            Blueprint Uploader
          </button>
        </nav>
      </header>
      <main className="App-content">
        {renderActiveComponent()}
      </main>
    </div>
  );
}

export default App;
